"use client"
import * as React from "react"
import { Canvas, useFrame } from "@react-three/fiber"
import { Float, MeshTransmissionMaterial, Environment, Stars } from "@react-three/drei"
import * as THREE from "three"

// Each crystal shape is fully autonomous ÔÇô no scroll influence, just pure organic floating
const crystalShapes = [
    // Icosahedrons (multifaceted gems)
    { id: "ico1", geometry: "icosahedron", args: [1.4, 0] as [number, number], pos: [-5.5, 3, -8] as [number, number, number], speed: 1.8, ri: 1.2, fi: 2.5, color: "#ffffff", thi: 2.0, rough: 0.05 },
    { id: "ico2", geometry: "icosahedron", args: [0.9, 0] as [number, number], pos: [6, -4, -6] as [number, number, number], speed: 2.4, ri: 1.8, fi: 1.8, color: "#a78bfa", thi: 1.8, rough: 0.07 },
    // Octahedrons (diamonds)
    { id: "oct1", geometry: "octahedron", args: [1.8, 0] as [number, number], pos: [5, 4.5, -9] as [number, number, number], speed: 1.2, ri: 2.0, fi: 2.0, color: "#38bdf8", thi: 2.5, rough: 0.04 },
    { id: "oct2", geometry: "octahedron", args: [1.1, 0] as [number, number], pos: [-7, -2, -7] as [number, number, number], speed: 2.2, ri: 1.5, fi: 1.5, color: "#f472b6", thi: 1.5, rough: 0.08 },
    { id: "oct3", geometry: "octahedron", args: [0.7, 0] as [number, number], pos: [2, 7, -5] as [number, number, number], speed: 3.0, ri: 2.5, fi: 2.0, color: "#4ade80", thi: 1.2, rough: 0.06 },
    // Tetrahedrons (pyramids)
    { id: "tet1", geometry: "tetrahedron", args: [2.0, 0] as [number, number], pos: [-3, 6, -12] as [number, number, number], speed: 1.0, ri: 0.8, fi: 1.2, color: "#ffffff", thi: 3.0, rough: 0.03 },
    { id: "tet2", geometry: "tetrahedron", args: [1.3, 0] as [number, number], pos: [8, -6, -10] as [number, number, number], speed: 1.6, ri: 1.4, fi: 1.8, color: "#fb923c", thi: 2.0, rough: 0.06 },
    { id: "tet3", geometry: "tetrahedron", args: [0.8, 0] as [number, number], pos: [-8, 5, -6] as [number, number, number], speed: 2.5, ri: 2.0, fi: 2.5, color: "#facc15", thi: 1.5, rough: 0.08 },
    // Dodecahedrons (complex multi-face)
    { id: "dod1", geometry: "dodecahedron", args: [1.6, 0] as [number, number], pos: [3, -8, -11] as [number, number, number], speed: 1.4, ri: 1.6, fi: 1.4, color: "#818cf8", thi: 2.5, rough: 0.05 },
    { id: "dod2", geometry: "dodecahedron", args: [0.9, 0] as [number, number], pos: [-5, -8, -9] as [number, number, number], speed: 2.0, ri: 2.2, fi: 2.2, color: "#2dd4bf", thi: 1.8, rough: 0.07 },
    // Boxes (cubes)
    { id: "box1", geometry: "box", args: [2.2, 2.2, 2.2] as any, pos: [7, 1, -11] as [number, number, number], speed: 1.0, ri: 1.2, fi: 1.0, color: "#ffffff", thi: 2.8, rough: 0.02 },
    { id: "box2", geometry: "box", args: [1.2, 1.2, 1.2] as any, pos: [-2, -6, -7] as [number, number, number], speed: 2.2, ri: 2.0, fi: 2.0, color: "#c084fc", thi: 2.0, rough: 0.06 },
    { id: "box3", geometry: "box", args: [0.8, 0.8, 0.8] as any, pos: [0, 9, -6] as [number, number, number], speed: 3.0, ri: 2.8, fi: 2.5, color: "#34d399", thi: 1.5, rough: 0.08 },
    // Spheres (floating orbs)
    { id: "sph1", geometry: "sphere", args: [2.5, 32, 32] as any, pos: [-1, -14, -18] as [number, number, number], speed: 0.8, ri: 3.0, fi: 0.8, color: "#ffffff", thi: 3.5, rough: 0.02 },
    { id: "sph2", geometry: "sphere", args: [1.0, 24, 24] as any, pos: [9, 8, -9] as [number, number, number], speed: 2.0, ri: 2.0, fi: 2.5, color: "#60a5fa", thi: 2.0, rough: 0.05 },
    { id: "sph3", geometry: "sphere", args: [0.6, 16, 16] as any, pos: [-9, 1, -7] as [number, number, number], speed: 3.5, ri: 3.0, fi: 3.0, color: "#f87171", thi: 1.5, rough: 0.08 },
]

function makeGeometry(shape: string, args: any) {
    switch (shape) {
        case "icosahedron": return <icosahedronGeometry args={args} />
        case "octahedron": return <octahedronGeometry args={args} />
        case "tetrahedron": return <tetrahedronGeometry args={args} />
        case "dodecahedron": return <dodecahedronGeometry args={args} />
        case "box": return <boxGeometry args={args} />
        case "sphere": return <sphereGeometry args={args} />
        default: return <icosahedronGeometry args={args} />
    }
}

function CrystalShape({ shape }: { shape: typeof crystalShapes[0] }) {
    const meshRef = React.useRef<THREE.Mesh>(null)

    // Each crystal has its own unique autonomous rotation ÔÇô NOT scroll-based
    const rotSpeed = React.useRef({
        x: (Math.random() - 0.5) * 0.004,
        y: (Math.random() - 0.5) * 0.006,
        z: (Math.random() - 0.5) * 0.003,
    })

    useFrame(() => {
        if (!meshRef.current) return
        meshRef.current.rotation.x += rotSpeed.current.x
        meshRef.current.rotation.y += rotSpeed.current.y
        meshRef.current.rotation.z += rotSpeed.current.z
    })

    return (
        <Float
            speed={shape.speed}
            rotationIntensity={shape.ri}
            floatIntensity={shape.fi}
        >
            <mesh ref={meshRef} position={shape.pos}>
                {makeGeometry(shape.geometry, shape.args)}
                <MeshTransmissionMaterial
                    color={shape.color}
                    resolution={256}
                    thickness={shape.thi}
                    roughness={shape.rough}
                    transmission={1}
                    ior={1.5}
                    chromaticAberration={0.08}
                    backside={true}
                />
            </mesh>
        </Float>
    )
}

export function Background3D() {
    return (
        <div className="fixed inset-0 z-[-10] pointer-events-none">
            <Canvas camera={{ position: [0, 0, 10], fov: 55 }}>
                <Environment preset="city" />
                <ambientLight intensity={0.4} />
                <directionalLight position={[10, 10, 5]} intensity={1.2} />
                <pointLight position={[-10, -5, 5]} color="#818cf8" intensity={0.8} />
                <pointLight position={[10, 5, -5]} color="#38bdf8" intensity={0.6} />

                {crystalShapes.map(shape => (
                    <CrystalShape key={shape.id} shape={shape} />
                ))}

                <Stars radius={60} depth={50} count={300} factor={3} saturation={1} fade speed={0.3} />
            </Canvas>
        </div>
    )
}

"use client"
import * as React from "react"
import { useRef, useState } from "react"
import { profile } from "@/data/profile"
import gsap from "gsap"
import { useGSAP } from "@gsap/react"
import { Code2, PenTool, Rocket, Heart, ArrowRight, Sparkles, GraduationCap, Briefcase } from "lucide-react"
import { useLanguage } from "@/context/LanguageContext"

const stats = [
    { value: "+2", label: { es: "A├▒os de Experiencia", en: "Years of Experience" }, color: "#61DAFB", bg: "#61DAFB15" },
    { value: "+12", label: { es: "Proyectos Completados", en: "Projects Completed" }, color: "#3ECF8E", bg: "#3ECF8E15" },
    { value: "+10", label: { es: "Tecnolog├¡as de Vanguardia", en: "Active Technologies" }, color: "#b561d6ff", bg: "#9B59B615" },
    { value: "100%", label: { es: "Orientado a Resultados", en: "Results-Oriented" }, color: "#e6825aff", bg: "#F7DF1E15" },
]

const highlights = [
    {
        icon: GraduationCap,
        color: "#3178C6",
        gradient: "from-[#3178C6]/20 to-[#3178C6]/5",
        title: { es: "Ingenier├¡a de Sistemas", en: "Systems Engineering" },
        desc: { es: "Estudios en ingiener├¡a con bases s├│lidas en algoritmos, redes y arquitectura de software", en: "Studies at UTP with solid foundations in algorithms, networks and software architecture" }
    },
    {
        icon: Code2,
        color: "#61DAFB",
        gradient: "from-[#61DAFB]/20 to-[#61DAFB]/5",
        title: { es: "C├│digo de Calidad", en: "Quality Code" },
        desc: { es: "C├│digo limpio, estricto y arquitectura escalable en cada proyecto", en: "Clean code, strict TypeScript and scalable architecture in every project" }
    },
    {
        icon: PenTool,
        color: "#F24E1E",
        gradient: "from-[#F24E1E]/20 to-[#F24E1E]/5",
        title: { es: "Dise├▒o y UX", en: "Design & UX" },
        desc: { es: "Interfaz que impresionan, convierten y se adaptan a cualquier dispositivo", en: "Interfaces that impress, convert and adapt to any device" }
    },
    {
        icon: Briefcase,
        color: "#3ECF8E",
        gradient: "from-[#3ECF8E]/20 to-[#3ECF8E]/5",
        title: { es: "Experiencia Real", en: "Real Experience" },
        desc: { es: "Proyectos para clientes reales: aplicaciones, webs corporativas y plataformas escalables", en: "Projects for real clients: corporate sites and scalable platforms" }
    },
    {
        icon: Rocket,
        color: "#9B59B6",
        gradient: "from-[#9B59B6]/20 to-[#9B59B6]/5",
        title: { es: "Deployment & DevOps", en: "Deployment & DevOps" },
        desc: { es: "Vercel, Docker, CI/CD y despliegue continuo con buenas pr├ícticas", en: "Vercel, Docker, CI/CD and continuous deployment with best practices" }
    },
    {
        icon: Heart,
        color: "#E74C3C",
        gradient: "from-[#E74C3C]/20 to-[#E74C3C]/5",
        title: { es: "Pasi├│n por lo Digital", en: "Passion for Digital" },
        desc: { es: "Aprendizaje continuo, open source y mentalidad de crecimiento growth", en: "Continuous learning, open source contributions and a growth mindset" }
    },
]

export function About() {
    const sectionRef = useRef<HTMLElement>(null)
    const { language } = useLanguage()
    const [activeCard, setActiveCard] = useState<number | null>(null)

    useGSAP(() => {
        gsap.fromTo(".about-badge",
            { opacity: 0, y: 20, scale: 0.9 },
            { opacity: 1, y: 0, scale: 1, duration: 0.6, ease: "back.out(1.7)", scrollTrigger: { trigger: ".about-badge", start: "top 85%" } }
        )
        gsap.fromTo(".about-title",
            { opacity: 0, y: 40 },
            { opacity: 1, y: 0, duration: 1, ease: "power3.out", scrollTrigger: { trigger: ".about-title", start: "top 80%" } }
        )
        gsap.fromTo(".about-desc",
            { opacity: 0, y: 20 },
            { opacity: 1, y: 0, duration: 0.8, delay: 0.2, ease: "power2.out", scrollTrigger: { trigger: ".about-desc", start: "top 82%" } }
        )
        gsap.fromTo(".about-stat",
            { opacity: 0, y: 40, scale: 0.8 },
            {
                opacity: 1, y: 0, scale: 1,
                duration: 0.7, stagger: 0.12, ease: "back.out(1.5)",
                scrollTrigger: { trigger: ".about-stats-row", start: "top 85%" }
            }
        )
        gsap.fromTo(".about-highlight",
            { opacity: 0, y: 30 },
            {
                opacity: 1, y: 0,
                duration: 0.6, stagger: 0.1, ease: "power2.out",
                scrollTrigger: { trigger: ".about-highlights-grid", start: "top 85%" }
            }
        )
        gsap.fromTo(".about-cta",
            { opacity: 0, y: 20 },
            { opacity: 1, y: 0, duration: 0.8, ease: "power2.out", scrollTrigger: { trigger: ".about-cta", start: "top 90%" } }
        )
    }, { scope: sectionRef })

    return (
        <section ref={sectionRef} id="about" className="py-16 relative overflow-hidden">
            {/* Layered ambient glows */}
            <div className="absolute top-1/3 left-1/4 w-[500px] h-[500px] bg-blue-500/5 rounded-full blur-[130px] -z-10 animate-pulse" />
            <div className="absolute bottom-1/4 right-1/4 w-[400px] h-[400px] bg-purple-500/5 rounded-full blur-[120px] -z-10 animate-pulse" style={{ animationDelay: "1s" }} />

            <div className="container px-4 md:px-8 max-w-6xl mx-auto">

                {/* Header ÔÇö Centered, full-width */}
                <div className="text-center mb-20">
                    <div className="about-badge opacity-0 inline-flex items-center gap-2 px-4 py-2 rounded-full text-xs font-semibold font-mono mb-6 text-primary">

                    </div>
                    <h2 className="about-title opacity-0 text-4xl md:text-6xl font-bold tracking-tight mb-8 leading-tight text-white">
                        {language === "es" ? "Sobre m├¡" : "About me"}
                    </h2>
                    <div className="about-desc opacity-0 max-w-3xl mx-auto">
                        <p className="text-xl text-white leading-relaxed">
                            {language === "es"
                                ? profile.about
                                : "I'm a developer committed to building functional, fast, and visually stunning interfaces. A Systems Engineering student at UTP with hands-on experience in real-world projects ÔÇö from corporate websites to mobile platforms."}
                        </p>
                    </div>
                </div>

                {/* Stats Row */}
                <div className="about-stats-row grid grid-cols-2 lg:grid-cols-4 gap-5 mb-24">
                    {stats.map((stat) => (
                        <div
                            key={stat.value}
                            className="about-stat opacity-0 relative glass-panel rounded-3xl p-7 text-center group cursor-default overflow-hidden transition-all duration-500 hover:-translate-y-2 hover:shadow-2xl"
                            style={{ boxShadow: `0 0 0 0 ${stat.color}` }}
                            onMouseEnter={e => {
                                (e.currentTarget as HTMLElement).style.boxShadow = `0 0 40px 0 ${stat.color}25`
                            }}
                            onMouseLeave={e => {
                                (e.currentTarget as HTMLElement).style.boxShadow = `0 0 0 0 ${stat.color}`
                            }}
                        >
                            {/* Colored glow disc */}
                            <div
                                className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-500 blur-2xl -z-10"
                                style={{ background: `radial-gradient(circle at center, ${stat.color}25, transparent 70%)` }}
                            />
                            {/* Top accent line */}
                            <div
                                className="absolute top-0 left-1/2 -translate-x-1/2 w-12 h-0.5 rounded-full transition-all duration-500 group-hover:w-full"
                                style={{ backgroundColor: stat.color }}
                            />
                            <p
                                className="text-5xl md:text-6xl font-black mb-2 transition-transform duration-300 group-hover:scale-110"
                                style={{ color: stat.color }}
                            >
                                {stat.value}
                            </p>
                            <p className="text-sm text-muted-foreground font-medium leading-snug">
                                {stat.label[language]}
                            </p>
                        </div>
                    ))}
                </div>

                {/* Highlights Grid */}
                <div className="about-highlights-grid grid md:grid-cols-2 lg:grid-cols-3 gap-5 mb-20">
                    {highlights.map((item, i) => (
                        <div
                            key={item.title.es}
                            className={`about-highlight opacity-0 relative glass-panel rounded-3xl p-7 cursor-default overflow-hidden transition-all duration-500 hover:-translate-y-2 group`}
                            onMouseEnter={() => setActiveCard(i)}
                            onMouseLeave={() => setActiveCard(null)}
                            style={{
                                boxShadow: activeCard === i ? `0 20px 60px 0 ${item.color}20` : undefined
                            }}
                        >
                            {/* Dynamic colored background on hover */}
                            <div
                                className={`absolute inset-0 bg-gradient-to-br ${item.gradient} opacity-0 group-hover:opacity-100 transition-opacity duration-500 -z-10`}
                            />
                            {/* Top colored accent bar */}
                            <div
                                className="absolute top-0 left-0 w-full h-0.5 opacity-0 group-hover:opacity-100 transition-opacity duration-500"
                                style={{ background: `linear-gradient(90deg, ${item.color}, transparent)` }}
                            />

                            <div className="flex flex-col gap-5">
                                {/* Icon with glowing ring */}
                                <div className="relative w-fit">
                                    <div
                                        className="w-14 h-14 rounded-2xl flex items-center justify-center transition-transform duration-300 group-hover:scale-110 group-hover:rotate-3"
                                        style={{ backgroundColor: `${item.color}20`, border: `1px solid ${item.color}30` }}
                                    >
                                        <item.icon className="w-7 h-7 transition-transform duration-300" style={{ color: item.color }} />
                                    </div>
                                    {/* Glow ring on hover */}
                                    <div
                                        className="absolute inset-0 rounded-2xl opacity-0 group-hover:opacity-50 transition-opacity duration-500 blur-md"
                                        style={{ backgroundColor: item.color }}
                                    />
                                </div>

                                <div>
                                    <p className="text-lg font-bold mb-2 group-hover:text-white transition-colors duration-300">
                                        {item.title[language]}
                                    </p>
                                    <p className="text-sm text-muted-foreground leading-relaxed group-hover:text-foreground/80 transition-colors duration-300">
                                        {item.desc[language]}
                                    </p>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                {/* CTA */}
                <div className="about-cta opacity-0 text-center">
                    <a
                        href="#contact"
                        className="inline-flex items-center gap-3 px-10 py-5 rounded-full text-base font-bold group transition-all duration-500 relative overflow-hidden"
                        style={{
                            background: "linear-gradient(135deg, rgba(97,218,251,0.15), rgba(155,89,182,0.15))",
                            border: "1px solid rgba(97,218,251,0.3)"
                        }}
                        onMouseEnter={e => {
                            (e.currentTarget as HTMLElement).style.background = "linear-gradient(135deg, rgba(97,218,251,0.3), rgba(155,89,182,0.3))"
                                ; (e.currentTarget as HTMLElement).style.transform = "translateY(-4px)"
                                ; (e.currentTarget as HTMLElement).style.boxShadow = "0 20px 60px rgba(97,218,251,0.2)"
                        }}
                        onMouseLeave={e => {
                            (e.currentTarget as HTMLElement).style.background = "linear-gradient(135deg, rgba(97,218,251,0.15), rgba(155,89,182,0.15))"
                                ; (e.currentTarget as HTMLElement).style.transform = "translateY(0)"
                                ; (e.currentTarget as HTMLElement).style.boxShadow = "none"
                        }}
                    >
                        <span className="text-white">
                            {language === "es" ? "┬┐Hablamos de tu pr├│ximo proyecto?" : "Let's talk about your next project"}
                        </span>
                        <ArrowRight className="w-5 h-5 text-white-400 transition-transform duration-300 group-hover:translate-x-2" />
                    </a>
                </div>

            </div>
        </section>
    )
}

"use client"
import * as React from "react"
import { useRef } from "react"
import { profile } from "@/data/profile"
import { MapPin, Mail, MessageCircle, Sparkles, ArrowRight } from "lucide-react"
import gsap from "gsap"
import { useGSAP } from "@gsap/react"
import { useLanguage } from "@/context/LanguageContext"

export function Contact() {
    const sectionRef = useRef<HTMLElement>(null)
    const { language } = useLanguage()

    useGSAP(() => {
        gsap.fromTo(".contact-header",
            { opacity: 0, y: 30 },
            {
                opacity: 1,
                y: 0,
                duration: 0.8,
                ease: "power2.out",
                scrollTrigger: {
                    trigger: ".contact-header",
                    start: "top 80%",
                }
            }
        )

        gsap.fromTo(".contact-card",
            { opacity: 0, scale: 0.9, y: 20 },
            {
                opacity: 1,
                scale: 1,
                y: 0,
                duration: 0.8,
                stagger: 0.15,
                ease: "back.out(1.4)",
                scrollTrigger: {
                    trigger: ".contact-grid",
                    start: "top 75%",
                }
            }
        )
    }, { scope: sectionRef })

    const contactMethods = [
        {
            icon: MessageCircle,
            title: language === "es" ? "WhatsApp" : "WhatsApp",
            value: profile.phone,
            link: profile.social.whatsapp,
            label: language === "es" ? "Chatear ahora" : "Chat now",
            color: "#25D366"
        },
        {
            icon: Mail,
            title: language === "es" ? "Correo electr├│nico" : "Email",
            value: profile.email,
            link: `mailto:${profile.email}`,
            label: language === "es" ? "Enviar correo" : "Send email",
            color: "#EA4335"
        },
        {
            icon: MapPin,
            title: language === "es" ? "Ubicaci├│n" : "Location",
            value: profile.location,
            link: "#",
            label: language === "es" ? "Arequipa, Per├║" : "Arequipa, Peru",
            color: "#4285F4"
        }
    ]

    return (
        <section ref={sectionRef} id="contact" className="py-16 relative overflow-hidden">
            {/* Background elements */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-primary/5 rounded-full blur-[120px] -z-10" />

            <div className="container px-4 md:px-8 max-w-5xl mx-auto">
                <div className="contact-header mb-16 text-center opacity-0">
                    <h2 className="text-4xl md:text-5xl font-bold tracking-tight mb-6 text-white text-center">
                        {language === "es" ? "┬íHablemos de tu pr├│ximo proyecto!" : "Let's talk about your next project!"}
                    </h2>
                    <p className="text-xl text-muted-foreground max-w-2xl mx-auto leading-relaxed">
                        {language === "es"
                            ? "Estoy disponible para nuevos proyectos y colaboraciones. Elige el canal que prefieras y me pondr├® en contacto contigo de inmediato."
                            : "I'm available for new projects and collaborations. Choose your preferred channel and I'll get back to you immediately."}
                    </p>
                </div>

                <div className="contact-grid grid md:grid-cols-3 gap-6">
                    {contactMethods.map((method) => (
                        <a
                            key={method.title}
                            href={method.link}
                            target={method.link.startsWith("http") ? "_blank" : undefined}
                            rel={method.link.startsWith("http") ? "noreferrer" : undefined}
                            className="contact-card opacity-0 glass-panel p-8 rounded-3xl flex flex-col items-center text-center group hover:-translate-y-2 transition-all duration-500 hover:shadow-2xl hover:shadow-primary/10 border border-white/5 hover:border-white/20"
                        >
                            <div
                                className="w-16 h-16 rounded-2xl flex items-center justify-center mb-6 transition-transform duration-500 group-hover:scale-110 group-hover:rotate-6 shadow-lg"
                                style={{ backgroundColor: `${method.color}20`, border: `1px solid ${method.color}40` }}
                            >
                                <method.icon className="w-7 h-7" style={{ color: method.color }} />
                            </div>

                            <h3 className="text-xl font-bold mb-2 text-white">{method.title}</h3>
                            <p className="text-muted-foreground mb-6 font-medium">{method.value}</p>

                            <div className="mt-auto flex items-center gap-2 text-sm font-bold text-white group-hover:text-primary transition-colors">
                                <span>{method.label}</span>
                                <ArrowRight className="w-4 h-4 transition-transform duration-300 group-hover:translate-x-1" />
                            </div>
                        </a>
                    ))}
                </div>

                <div className="mt-20 text-center">
                    <p className="text-muted-foreground font-mono text-sm uppercase tracking-widest">
                        Arequipa, Per├║ ÔÇó {language === "es" ? "Disponible Remoto" : "Available Remote"}
                    </p>
                </div>
            </div>
        </section>
    )
}

"use client"
import * as React from "react"
import Link from "next/link"
import { usePathname } from "next/navigation"
import { cn } from "@/lib/utils"
import { Menu, X, Globe } from "lucide-react"
import { Button } from "@/components/ui/button"
import { useLanguage } from "@/context/LanguageContext"
import { profile } from "@/data/profile"

export function Navbar() {
